# Node.js Streams

Streams are one of the most powerful and fundamental concepts in Node.js. They let you process data piece by piece, without loading entire datasets into memory. Every HTTP request, file read, compression operation, and child process in Node.js uses streams under the hood.

## The Four Stream Types

Node.js provides four types of streams, all defined in the `stream` module:

```
Readable          Writable          Transform            Duplex
+---------+      +---------+      +-----------+      +-----------+
| data -> | ---> | -> sink |      | data ->   |      | data ->   |
|  source |      |         |      | transform |      |           |
+---------+      +---------+      | -> output |      | <- data   |
                                  +-----------+      +-----------+

Examples:         Examples:         Examples:           Examples:
fs.createRead     fs.createWrite    zlib.createGzip     TCP socket
http.Incoming     http.ServerResp   crypto.createCipher net.Socket
process.stdin     process.stdout    stream.Transform    tls.TLSSocket
Readable.from()   process.stderr    PassThrough         WebSocket
```

- **Readable**: A source of data. You consume data from it. Examples: `fs.createReadStream()`, `http.IncomingMessage`, `process.stdin`, `Readable.from()`.
- **Writable**: A destination for data. You write data to it. Examples: `fs.createWriteStream()`, `http.ServerResponse`, `process.stdout`.
- **Transform**: A stream that reads input, transforms it, and produces output. It is both Readable and Writable. Examples: `zlib.createGzip()`, `crypto.createCipheriv()`, custom parsers.
- **Duplex**: A stream that is both Readable and Writable independently (the two sides are not connected). Examples: TCP sockets, `net.Socket`, `tls.TLSSocket`.

## Creating Readable Streams

### From Arrays and Iterables

```javascript
const { Readable } = require('stream');

// From an array
const readable = Readable.from(['hello', ' ', 'world']);
readable.on('data', (chunk) => process.stdout.write(chunk));

// From a generator
function* generateNumbers() {
  for (let i = 0; i < 100; i++) {
    yield `number: ${i}\n`;
  }
}
const numStream = Readable.from(generateNumbers());

// From an async generator
async function* fetchPages(urls) {
  for (const url of urls) {
    const res = await fetch(url);
    yield await res.text();
  }
}
const pageStream = Readable.from(fetchPages(['https://example.com']));
```

### Custom Readable with _read()

```javascript
const { Readable } = require('stream');

class CounterStream extends Readable {
  constructor(max, options) {
    super(options);
    this.max = max;
    this.current = 0;
  }

  _read(size) {
    if (this.current >= this.max) {
      this.push(null); // Signal end of stream
      return;
    }
    const data = `Count: ${this.current}\n`;
    this.push(data);
    this.current++;
  }
}

const counter = new CounterStream(10);
counter.pipe(process.stdout);
```

### From Files

```javascript
const fs = require('fs');

// Basic file read stream
const readStream = fs.createReadStream('large-file.csv', {
  encoding: 'utf8',
  highWaterMark: 64 * 1024, // 64KB chunks (default is 64KB)
});

readStream.on('data', (chunk) => {
  console.log(`Received ${chunk.length} bytes`);
});
readStream.on('end', () => console.log('Done reading'));
readStream.on('error', (err) => console.error('Read error:', err));
```

## Creating Writable Streams

### To Files

```javascript
const fs = require('fs');

const writeStream = fs.createWriteStream('output.txt', {
  encoding: 'utf8',
  highWaterMark: 16 * 1024, // 16KB buffer
});

writeStream.write('Hello, ');
writeStream.write('World!\n');
writeStream.end('Final line.\n'); // end() writes last chunk and closes

writeStream.on('finish', () => console.log('All data written'));
writeStream.on('error', (err) => console.error('Write error:', err));
```

### Custom Writable with _write()

```javascript
const { Writable } = require('stream');

class LogWriter extends Writable {
  _write(chunk, encoding, callback) {
    const line = chunk.toString();
    const timestamp = new Date().toISOString();
    process.stdout.write(`[${timestamp}] ${line}`);
    callback(); // Signal that writing is complete
  }

  _final(callback) {
    console.log('Stream finished');
    callback();
  }
}

const logger = new LogWriter();
logger.write('Application started\n');
logger.write('Processing data\n');
logger.end('Done\n');
```

### To HTTP Responses

```javascript
const http = require('http');
const fs = require('fs');

http.createServer((req, res) => {
  // res is a Writable stream
  res.writeHead(200, { 'Content-Type': 'text/plain' });

  // Stream a file directly to the response
  const fileStream = fs.createReadStream('data.txt');
  fileStream.pipe(res);
}).listen(3000);
```

## Transform Streams

Transform streams sit between a Readable and a Writable, modifying data as it passes through.

### Basic Transform

```javascript
const { Transform } = require('stream');

class UpperCaseTransform extends Transform {
  _transform(chunk, encoding, callback) {
    const upper = chunk.toString().toUpperCase();
    this.push(upper);
    callback();
  }

  _flush(callback) {
    // Called when there is no more data to consume
    this.push('\n--- END OF STREAM ---\n');
    callback();
  }
}

const upperCase = new UpperCaseTransform();
process.stdin.pipe(upperCase).pipe(process.stdout);
```

### CSV Line Parser Transform

```javascript
const { Transform } = require('stream');

class CSVParser extends Transform {
  constructor(options) {
    super({ ...options, objectMode: true });
    this.headers = null;
    this.buffer = '';
  }

  _transform(chunk, encoding, callback) {
    this.buffer += chunk.toString();
    const lines = this.buffer.split('\n');
    this.buffer = lines.pop(); // Keep incomplete line in buffer

    for (const line of lines) {
      if (!line.trim()) continue;
      const values = line.split(',').map(v => v.trim());
      if (!this.headers) {
        this.headers = values;
      } else {
        const obj = {};
        this.headers.forEach((h, i) => obj[h] = values[i]);
        this.push(obj);
      }
    }
    callback();
  }

  _flush(callback) {
    if (this.buffer.trim()) {
      const values = this.buffer.split(',').map(v => v.trim());
      if (this.headers) {
        const obj = {};
        this.headers.forEach((h, i) => obj[h] = values[i]);
        this.push(obj);
      }
    }
    callback();
  }
}

// Usage:
// fs.createReadStream('data.csv').pipe(new CSVParser())
```

### Compression with zlib Transform

```javascript
const fs = require('fs');
const zlib = require('zlib');
const { pipeline } = require('stream/promises');

// Compress a file
async function compressFile(input, output) {
  await pipeline(
    fs.createReadStream(input),
    zlib.createGzip({ level: 9 }),
    fs.createWriteStream(output)
  );
  console.log(`Compressed ${input} -> ${output}`);
}

// Decompress a file
async function decompressFile(input, output) {
  await pipeline(
    fs.createReadStream(input),
    zlib.createGunzip(),
    fs.createWriteStream(output)
  );
  console.log(`Decompressed ${input} -> ${output}`);
}

compressFile('data.json', 'data.json.gz');
```

## pipeline() for Safe Piping

The `.pipe()` method does not forward errors or clean up properly. Always use `pipeline()` instead.

### Callback-based pipeline

```javascript
const { pipeline } = require('stream');
const fs = require('fs');
const zlib = require('zlib');

pipeline(
  fs.createReadStream('input.txt'),
  zlib.createGzip(),
  fs.createWriteStream('input.txt.gz'),
  (err) => {
    if (err) {
      console.error('Pipeline failed:', err);
    } else {
      console.log('Pipeline succeeded');
    }
  }
);
```

### Promise-based pipeline (preferred)

```javascript
const { pipeline } = require('stream/promises');
const fs = require('fs');
const zlib = require('zlib');
const { Transform } = require('stream');

async function processFile() {
  const lineCounter = new Transform({
    transform(chunk, encoding, callback) {
      const lines = chunk.toString().split('\n').length - 1;
      this.lineCount = (this.lineCount || 0) + lines;
      callback(null, chunk);
    }
  });

  try {
    await pipeline(
      fs.createReadStream('input.txt'),
      lineCounter,
      zlib.createGzip(),
      fs.createWriteStream('output.txt.gz')
    );
    console.log(`Processed ${lineCounter.lineCount} lines`);
  } catch (err) {
    console.error('Pipeline failed:', err);
  }
}
```

### Pipeline with multiple transforms

```javascript
const { pipeline } = require('stream/promises');
const { createReadStream, createWriteStream } = require('fs');
const { createGzip } = require('zlib');
const { Transform } = require('stream');

const addTimestamp = new Transform({
  transform(chunk, enc, cb) {
    const lines = chunk.toString().split('\n');
    const stamped = lines
      .filter(l => l.trim())
      .map(l => `[${new Date().toISOString()}] ${l}`)
      .join('\n') + '\n';
    cb(null, stamped);
  }
});

const filterErrors = new Transform({
  transform(chunk, enc, cb) {
    const lines = chunk.toString().split('\n');
    const errors = lines.filter(l => l.includes('ERROR')).join('\n');
    if (errors) cb(null, errors + '\n');
    else cb();
  }
});

await pipeline(
  createReadStream('application.log'),
  filterErrors,
  addTimestamp,
  createGzip(),
  createWriteStream('errors.log.gz')
);
```

## Async Iteration with `for await...of`

All Readable streams are async iterables. This is the most modern and ergonomic way to consume stream data.

```javascript
const fs = require('fs');

async function processLines(filename) {
  const stream = fs.createReadStream(filename, { encoding: 'utf8' });
  let lineCount = 0;

  for await (const chunk of stream) {
    const lines = chunk.split('\n');
    for (const line of lines) {
      if (line.trim()) {
        lineCount++;
        // Process each line
      }
    }
  }
  console.log(`Total lines: ${lineCount}`);
}
```

### Async iteration with readline for line-by-line

```javascript
const fs = require('fs');
const readline = require('readline');

async function processFileLineByLine(filename) {
  const rl = readline.createInterface({
    input: fs.createReadStream(filename),
    crlfDelay: Infinity,
  });

  let lineNumber = 0;
  for await (const line of rl) {
    lineNumber++;
    if (line.startsWith('#')) continue; // Skip comments
    console.log(`Line ${lineNumber}: ${line}`);
  }
}
```

### Collecting stream data

```javascript
const { Readable } = require('stream');

// Node.js 18+ — built-in method
const stream = fs.createReadStream('data.json');
const buffer = await stream.toArray();
// Or as a single Buffer
const data = Buffer.concat(await stream.toArray());

// Manual collection
async function collectStream(readable) {
  const chunks = [];
  for await (const chunk of readable) {
    chunks.push(chunk);
  }
  return Buffer.concat(chunks);
}
```

## Backpressure Handling

Backpressure occurs when a Writable stream cannot consume data as fast as a Readable stream produces it. Node.js streams handle this automatically when you use `pipeline()`, but you must handle it manually when calling `.write()` directly.

```javascript
const fs = require('fs');

const readable = fs.createReadStream('huge-file.bin');
const writable = fs.createWriteStream('copy.bin');

// WRONG: ignoring backpressure
readable.on('data', (chunk) => {
  writable.write(chunk); // May buffer unboundedly in memory!
});

// RIGHT: respecting backpressure manually
readable.on('data', (chunk) => {
  const canContinue = writable.write(chunk);
  if (!canContinue) {
    // Writable buffer is full, pause the readable
    readable.pause();
    writable.once('drain', () => {
      // Writable buffer has drained, resume reading
      readable.resume();
    });
  }
});

// BEST: use pipeline() which handles backpressure automatically
const { pipeline } = require('stream/promises');
await pipeline(readable, writable);
```

### Understanding highWaterMark

```javascript
const { Readable, Writable } = require('stream');

// highWaterMark is the buffer size threshold (in bytes for Buffer mode,
// or number of objects for objectMode).
// Default: 16KB for Writable, 64KB for Readable (16 for objectMode)

const readable = new Readable({
  highWaterMark: 1024, // 1KB buffer before backpressure
  read(size) { /* ... */ }
});

const writable = new Writable({
  highWaterMark: 1024, // 1KB buffer before .write() returns false
  write(chunk, encoding, callback) { /* ... */ }
});
```

## Object Mode Streams

By default, streams work with `Buffer` and `string` data. Object mode lets streams pass any JavaScript value.

```javascript
const { Transform, Readable, Writable } = require('stream');

// Readable that produces objects
const userStream = new Readable({
  objectMode: true,
  read() {
    this.push({ name: 'Alice', age: 30 });
    this.push({ name: 'Bob', age: 25 });
    this.push(null);
  }
});

// Transform that filters objects
const adultFilter = new Transform({
  objectMode: true,
  transform(user, encoding, callback) {
    if (user.age >= 18) {
      this.push(user);
    }
    callback();
  }
});

// Writable that consumes objects
const printer = new Writable({
  objectMode: true,
  write(user, encoding, callback) {
    console.log(`${user.name} (${user.age})`);
    callback();
  }
});

userStream.pipe(adultFilter).pipe(printer);
```

## Common Patterns

### File Copy

```javascript
const { pipeline } = require('stream/promises');
const { createReadStream, createWriteStream } = require('fs');

async function copyFile(src, dest) {
  await pipeline(
    createReadStream(src),
    createWriteStream(dest)
  );
}
```

### HTTP Proxy

```javascript
const http = require('http');
const { pipeline } = require('stream');

http.createServer((clientReq, clientRes) => {
  const proxyReq = http.request({
    hostname: 'api.example.com',
    port: 80,
    path: clientReq.url,
    method: clientReq.method,
    headers: clientReq.headers,
  }, (proxyRes) => {
    clientRes.writeHead(proxyRes.statusCode, proxyRes.headers);
    pipeline(proxyRes, clientRes, (err) => {
      if (err) console.error('Proxy pipeline error:', err);
    });
  });

  pipeline(clientReq, proxyReq, (err) => {
    if (err) console.error('Request pipeline error:', err);
  });
}).listen(8080);
```

### Gzip Compression Middleware

```javascript
const http = require('http');
const zlib = require('zlib');
const fs = require('fs');
const { pipeline } = require('stream');

http.createServer((req, res) => {
  const acceptEncoding = req.headers['accept-encoding'] || '';
  const raw = fs.createReadStream('index.html');

  if (acceptEncoding.includes('gzip')) {
    res.writeHead(200, { 'Content-Encoding': 'gzip' });
    pipeline(raw, zlib.createGzip(), res, (err) => {
      if (err) console.error(err);
    });
  } else {
    res.writeHead(200);
    pipeline(raw, res, (err) => {
      if (err) console.error(err);
    });
  }
}).listen(3000);
```

### JSON Line (NDJSON) Processing

```javascript
const { Transform } = require('stream');
const { pipeline } = require('stream/promises');
const fs = require('fs');

class NDJSONParse extends Transform {
  constructor() {
    super({ readableObjectMode: true });
    this.buffer = '';
  }

  _transform(chunk, encoding, callback) {
    this.buffer += chunk.toString();
    const lines = this.buffer.split('\n');
    this.buffer = lines.pop();
    for (const line of lines) {
      if (line.trim()) {
        try {
          this.push(JSON.parse(line));
        } catch (e) {
          return callback(new Error(`Invalid JSON: ${line}`));
        }
      }
    }
    callback();
  }

  _flush(callback) {
    if (this.buffer.trim()) {
      try {
        this.push(JSON.parse(this.buffer));
      } catch (e) {
        return callback(new Error(`Invalid JSON: ${this.buffer}`));
      }
    }
    callback();
  }
}

// Usage: process a large NDJSON log file
async function processLogs() {
  const parser = new NDJSONParse();
  const reader = fs.createReadStream('events.ndjson');

  reader.pipe(parser);
  for await (const event of parser) {
    console.log(event.type, event.timestamp);
  }
}
```

### PassThrough for Tapping

```javascript
const { PassThrough } = require('stream');
const { pipeline } = require('stream/promises');
const fs = require('fs');

// PassThrough lets you observe data without modifying it
const monitor = new PassThrough();
let totalBytes = 0;

monitor.on('data', (chunk) => {
  totalBytes += chunk.length;
});
monitor.on('end', () => {
  console.log(`Total bytes transferred: ${totalBytes}`);
});

await pipeline(
  fs.createReadStream('largefile.bin'),
  monitor,
  fs.createWriteStream('copy.bin')
);
```

## Error Handling

Always handle stream errors. Unhandled stream errors crash the process.

```javascript
// With pipeline() — errors are forwarded to the callback/promise
const { pipeline } = require('stream/promises');
try {
  await pipeline(readable, transform, writable);
} catch (err) {
  console.error('Stream pipeline failed:', err.message);
}

// With events — attach error handlers to each stream
readable.on('error', handleError);
transform.on('error', handleError);
writable.on('error', handleError);

// With stream.finished() — detect when a stream is done or errored
const { finished } = require('stream/promises');
try {
  await finished(someStream);
  console.log('Stream completed successfully');
} catch (err) {
  console.error('Stream errored:', err);
}
```

## Web Streams Interop (Node.js 18+)

Node.js supports the Web Streams API (`ReadableStream`, `WritableStream`, `TransformStream`) and provides converters.

```javascript
const { Readable, Writable } = require('stream');

// Convert Node Readable to Web ReadableStream
const nodeReadable = fs.createReadStream('file.txt');
const webReadable = Readable.toWeb(nodeReadable);

// Convert Web ReadableStream to Node Readable
const response = await fetch('https://example.com');
const nodeStream = Readable.fromWeb(response.body);

for await (const chunk of nodeStream) {
  process.stdout.write(chunk);
}
```
